func newTemplateState(owner *templateState, templ tpl.Template, info templateInfo, id identity.Identity) *templateState {
	if id == nil {
		id = info
	}
	return &templateState{
		owner:		owner,
		info:		info,
		typ:		info.resolveType(),
		Template:	templ,
		parseInfo:	tpl.DefaultParseInfo,
		id:		id,
	}
}
